"""
Standalone patch — writes mkt-context for Isaiah 41-43.
Run: python3 scripts/zc-context-isaiah-41-43-patch.py
Chapters: 41 (29v), 42 (25v), 43 (28v) = 82 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "41": {
    "1": "<p>Isaiah 41:1 opens a divine courtroom scene: 'hachariyshu elai iyyim, be silent before me, O coastlands.' The charish (to be silent = the silence demanded of defendants before a court opens, cf. Hab 2:20: 'let all the earth be silent before him') addresses the iyyim (coastlands = the distant Mediterranean peoples; the same term as 40:15's 'drop in a bucket' — now summoned as defendants). 'Let the nations renew their strength; let them come near and then speak; let us together draw near for judgment' (yiggeshu az yedabberu yachdav lemishpat niqravah = they may draw near, then speak; together let us approach for judgment). The divine courtroom of chs.40-48 is the literary setting in which YHWH prosecutes the case that idols are nothing and he alone is God. The 'drawing near for judgment' is YHWH's offer of legal process — not unilateral assertion but open argument.</p>",
    "2": "<p>'Who has roused the conqueror from the east, whom victory meets at every step?' — the oracle points to a historical conqueror whom YHWH has mobilized. Most interpreters identify this as Cyrus II of Persia (Cyrus the Great, reigned 559-530 BCE), who conquered Media, Lydia (546 BCE under Croesus), and Babylon (539 BCE) in a remarkable sequence. Isaiah 44:28 and 45:1 name Cyrus explicitly. 'Victory meets at every step' (tsedek yiqre'enhu leraglav = righteousness/victory calls him at each footstep) = the Hebrew tsedek can mean both 'righteousness' and 'victory' — the divine righteousness meeting Cyrus at each stride makes him unstoppable. 'His sword makes them like dust, his bow like driven stubble' — the rapid devastation of Cyrus's armies: Sardis fell in two weeks (546 BCE), Babylon fell in a single battle (Opis, 539 BCE). The historical track record is the evidence YHWH presents in his courtroom.</p>",
    "3": "<p>'He pursues them and passes on safely, traveling paths his feet have never trodden before' — the speed and scope of the conqueror's campaigns: 'yirdefem ya'avor shalom, he pursues them and passes on in peace.' The unusual detail that Cyrus 'passes on safely' (shalom) despite traversing unknown terrain = YHWH's protection enabling the conqueror to move through unprecedented territory unharmed. Cyrus's campaigns covered what is now Iran, Turkey, Iraq, and Syria — genuinely 'paths his feet have never trodden before' for a Persian king. The verb 'trodden' (yavo) = to come/enter — the conquered territories had never been Persian domains before. The historical novelty of Cyrus's empire — the largest that had existed to that point — is YHWH's courtroom evidence of divine orchestration.</p>",
    "4": "<p>'Who has done this, calling the generations from the beginning? I, the LORD — I was first, and I am with the last; I am he' — the rhetorical question and its divine answer: 'mi-pa'al ve'asah, who has acted and done this?' The answer: 'ani YHWH ri'shon ve'et-acharonim ani-hu, I, YHWH, am the first, and with the last ones I am he.' The 'first and the last' (risohn... acharonim) formula = YHWH's existence encompasses the entire temporal span of history. He was present at creation (calling the first generation into being) and he will be present at the end (with the last). This formula is unique in the OT to Isaiah (44:6; 48:12) and is taken up in Rev 1:17; 2:8; 22:13 for the risen Christ: 'I am the first and the last.' 'Calling the generations from the beginning' (qore haggenerot mero'sh = calling/summoning the generations from the beginning) = YHWH's sovereign summons over all of history as the one who names and calls into being.</p>",
    "5": "<p>'The coastlands saw it and were afraid; the ends of the earth trembled; they drew near and came forward' — the nations' reaction to the evidence of YHWH's action through Cyrus: 'ra'u iyyim vayyira'u, the coastlands saw and were afraid.' The fear response to YHWH's power as mediated through historical events — the conquests of Cyrus that dismantled empire after empire created widespread fear among the remaining nations (the 'coastlands' and 'ends of the earth' = the most distant regions from the conquest). 'They drew near and came forward' (vayyiqrabu vayye'etayu = they drew near and came) — the drawing near is not repentance but the motion of defendants approaching the court, as commanded in v1. The irony: the nations were commanded to approach for judgment and they do so, but out of fear not contrition.</p>",
    "6": "<p>'Each one helps the other, and says to his companion, Take courage!' — the mutual encouragement of the idol-worshiping nations before the divine court: 'ish et-re'ehu ya'azoru ulechachiv yomar chazaq, each man helps his companion and says to his brother: be strong!' The chazaq (be strong! = the encouragement formula used before battle, Deut 31:6-7; Josh 1:6-9) applied ironically to idol-worshipers encouraging each other to persevere in their futile religion. The communal mutual encouragement (each one helps the other) is the social reinforcement that maintains idol-worship even when evidence against it accumulates. The contrast with v8-10 where YHWH encourages Israel ('be strong, do not fear, I will help you') is deliberate: human mutual encouragement vs. divine encouragement.</p>",
    "7": "<p>'The craftsman encourages the goldsmith; the one who smooths with the hammer encourages the one striking the anvil, saying of the soldering, It is good; and they fasten it with nails so that it cannot wobble' — the idol-manufacturing process described with deliberate irony: 'vaychazeq charash et-tsaref, and the craftsman strengthened/encouraged the goldsmith.' The process: (1) hammering smooth (melaqqed pattish = the one smoothing with the hammer); (2) striking the anvil (holam patish = striking the anvil); (3) evaluating the solder ('it is good' = tov hu, the creation-evaluation of Gen 1); (4) fastening with nails so it cannot wobble (veleso yimot = and it will not topple). The irony: the craftsmen use the encouragement language of YHWH's service (chazaq = strengthen, tov = good) for their futile manufacturing project. The nail-fastening so the idol 'won't wobble' echoes 40:20's 'idol that will not topple' — the craftsman's primary engineering challenge is structural stability for a supposed deity.</p>",
    "8": "<p>'But you, Israel, my servant, Jacob, whom I have chosen, offspring of Abraham my friend' — the adversative pivot from the coastlands' idol-manufacturing (vv5-7) to Israel's identity: 've'attah Yisrael avdi, but you, Israel, my servant.' Three identity-designations: (1) 'my servant' (avdi = the one in covenant-service relationship, the 'eved YHWH); (2) 'Jacob, whom I have chosen' (Ya'aqov asher bechartikha = Jacob whom I have chosen); (3) 'offspring of Abraham my friend' (zera Avraham ohavi = seed of Abraham my lover/friend). The ohavi (my friend/one who loves me) = one of only three OT texts calling Abraham YHWH's 'friend': 2 Chr 20:7 ('Abraham your friend forever'), Jas 2:23 ('he was called God's friend'). The identity of Israel as 'Abraham's offspring' grounds the current election in the ancient patriarchal covenant — the choosing of Israel did not begin in the Sinai-generation but in Abraham's call (Gen 12).</p>",
    "9": "<p>'You whom I took from the ends of the earth and called from its farthest regions, saying to you, You are my servant; I have chosen you and not rejected you' — the geographical scope of the divine call to Abraham: 'asher chelaztikhah miketsot ha'arets, whom I seized from the ends of the earth.' The chelaztikhah (I seized/took hold of = the forceful taking of someone by the arm, cf. 42:6: 'I will take hold of your hand') applied to YHWH's call of Abraham from Ur of the Chaldeans (the 'ends of the earth' = Mesopotamia, the farthest known region from Canaan's perspective). 'Called from its farthest regions' (umiatsileha qera'tikha, from its distant corners I called you) = the call of Abraham in Gen 12:1 ('go from your country, your people, your father's household'). The conclusion: 'I have chosen you and not rejected you' (bechartikha velo me'astikha, I chose you and did not spurn you). The divine non-rejection is the assurance for the exilic community: despite the exile (which could feel like rejection), the foundational choice stands.</p>",
    "10": "<p>'Do not fear, for I am with you; do not be dismayed, for I am your God; I will strengthen you; I will help you; I will uphold you with my righteous right hand' — the quintessential comfort oracle of Second Isaiah: 'al-tira ki-imkha ani, do not fear, for I am with you.' The five divine promises (with Hebrew): (1) imkha ani = I am with you; (2) Elohekha ani = I am your God; (3) imtiztikhah = I will strengthen you; (4) azartikhah = I will help you; (5) tamakhtikha bimin tsidqi = I have upheld you by my right hand of righteousness. The chiastic structure: 'do not fear' / 'I am with you' // 'do not be dismayed' / 'I am your God' / [five promises]. The al-tira (do not fear) is the standard divine comfort-formula of the patriarchal narratives (Gen 15:1; 26:24; 46:3) now given its fullest exposition: YHWH's presence (v10a), YHWH's identity as Israel's God (v10b), five active promises of support. The 'righteous right hand' (ymin tsidqi = right hand of my righteousness) = the hand that acts in accordance with YHWH's covenant-faithfulness.</p>",
    "11": "<p>'See — all who are enraged against you will be put to shame and disgraced; those who oppose you will come to nothing and perish' — the assurance of enemies' failure: 'hen yevoshu veyikkalemu kol hacharim bekha, see, they will be shamed and disgraced — all who are enraged against you.' The yevoshu (shame = the public exposure of failure before an audience, the social-death of honor-shame culture). 'Those who oppose you will come to nothing and perish' (yihyu ka'ayin veyo'vedu anshei rivekha = they will be as nothing and perish, the men of your legal dispute). The 'come to nothing' (ka'ayin = like a nothing/non-being) returns to 40:17's 'the nations are as nothing before him' — what is 'nothing' before YHWH becomes nothing when opposed to Israel under YHWH's protection. The legal language ('men of your dispute') continues the courtroom setting.</p>",
    "12": "<p>'You will seek your adversaries but will not find them; those who make war against you will be as nothing at all' — the complete disappearance of Israel's enemies: 'tevaqshhem velo timtsa'em anshei matsutekha, you will seek them and not find them, the men who contend with you.' The seeking-without-finding = the total disappearance of the enemy, contrasting with YHWH being found when sought (55:6: 'seek the LORD while he may be found'). 'Those who make war against you will be as nothing at all' (yihyu ke'ayin uchephes anshei milchamtekha = they will be as nothing and non-existent, the men of your war). The double non-existence: ka'ayin (like nothing) and kephes (like nothing/empty = a stronger term). The exiles' enemies — Babylon's imperial power, the garrison troops, the administrative officials who humiliated them — will simply not be there.</p>",
    "13": "<p>'For I, the LORD your God, hold your right hand; I am the one who says to you, Do not fear; I will help you' — the intimate divine hand-holding: 'ki ani YHWH Elohekha machaziq yeminekha, for I, YHWH your God, am grasping your right hand.' The machaziiq (grasping/holding firmly = from chazaq = to be strong, grip firmly, cf. 42:6: 'I will take hold of your hand and keep you'). YHWH holds Israel's right hand — the same right hand that YHWH upholds with his own right hand (v10: 'I uphold you with my righteous right hand'). The two right hands: YHWH's right hand upholds Israel; YHWH grasps Israel's right hand. The double assurance: from above and alongside simultaneously. 'I am the one who says to you: Do not fear; I will help you' (ha'omer lekha al-tira ani azartikhah = the one saying to you: do not fear, I have helped you) — the promise of help given in the perfect tense of accomplished fact (azartikhah = I have already helped you) even as the exile continues.</p>",
    "14": "<p>'Do not be afraid, O Jacob, you worm; you few men of Israel! I am the one who helps you, declares the LORD; your Redeemer is the Holy One of Israel' — the self-deprecating address that makes the comfort more astonishing: 'al-tiri tola'at Ya'aqov, do not be afraid, worm of Jacob.' The tola'at (worm/grub = the lowest form of animal life, a symbol of extreme vulnerability and weakness; Ps 22:6: 'I am a worm, not a man, scorned by everyone and despised by the people'). 'You few men of Israel' (metei Yisrael = the men of Israel = the small, diminished remnant in Babylon) — addressing the community at its most depleted. The comfort is proportional to the address: the more worm-like the exiles feel, the more startling the divine promise. 'Your Redeemer is the Holy One of Israel' (go'alekha qedosh Yisrael = your kinsman-redeemer is the Holy One of Israel). The go'el (redeemer = the kinsman who pays the redemption price for a family member sold into debt-slavery, Lev 25:25-49; Ruth 4) applied to YHWH — the divine kinsman who will buy Israel back from Babylonian captivity at the cost of allowing Cyrus's conquests (43:3).</p>",
    "15": "<p>'See — I will make you a new, sharp threshing sledge with many cutting edges; you will thresh the mountains and crush them, and reduce the hills to chaff' — the reversal of the worm into an instrument of power: 'hineh samtikha lemorag charuts chadash, behold I make you a threshing-sledge, a sharp new one.' The morag (threshing sledge = the heavy wooden sled, usually studded with sharp stones or iron pegs on its underside, dragged over harvested grain to separate kernel from stalk on the threshing floor). The 'worm of Jacob' becomes the threshing sledge. 'With many cutting edges' (ba'al piphiyot = master of mouths/edges = having many sharp edges on all sides). 'You will thresh the mountains and crush them' (tadush harim vetadoqem = you will thresh the mountains and reduce them to dust) — the mountains (the great empires: Babylon, Persia) reduced to chaff by YHWH's instrument Israel. The eschatological reversal: the humiliated become the instrument of judgment on the great.</p>",
    "16": "<p>'You will winnow them, and the wind will carry them away and the gale will scatter them; you will rejoice in the LORD and glory in the Holy One of Israel' — the completion of the threshing metaphor: 'tizrem veruach tissaem useara yaphits otam, you will winnow them and wind will carry them and a gale will scatter them.' The three-stage grain-processing: (1) threshing (v15 = separating the grain from the stalk by the sledge); (2) winnowing (tizrem = the throwing of the crushed material into the wind so the light chaff blows away); (3) scattering by gale (seara yaphits = a whirlwind scatters what remains). The wind carrying away the chaff-enemies = the natural consequence of the divine harvest, not a further act of violence. 'You will rejoice in the LORD and glory in the Holy One of Israel' (vetattah bin YHWH veveqedosh Yisrael tithalal = you will rejoice in YHWH and in the Holy One of Israel you will boast) — the jubilation of the harvested people: the harvest of judgment on enemies produces the harvest of joy for Israel.</p>",
    "17": "<p>'When the poor and the needy seek water and there is none, when their tongue is parched with thirst, I, the LORD, will answer them; I, the God of Israel, will not forsake them' — the water-promise oracle: 'haanevyonim ve'ha'evyonim mevaqshim mayim ve'ayin, the poor and the needy seek water and there is none.' The anivyim (poor = the economically vulnerable) and evyonim (the destitute needy = those who literally have nothing) = the exiles in their most desperate condition. The 'seeking water' may be literal (the desert journey of the return from Babylon) or metaphorical (seeking the life-sustaining presence of YHWH in exile). 'Their tongue parched with thirst' (nishsam tsama leshonam = their tongue dried up from thirst) — the physical extremity of dehydration as a figure for spiritual and social abandonment. 'I, the LORD, will answer them; I, the God of Israel, will not forsake them' (ani YHWH e'enehem Elohei Yisrael lo e'ezevem = I, YHWH, will answer them; the God of Israel, I will not abandon them) — the double divine identification with the double promise.</p>",
    "18": "<p>'I will open rivers on the bare heights and fountains in the middle of the valleys; I will turn the wilderness into a pool of water and the dry ground into springs' — the wilderness-transformation oracle: 'eftach al-shefiim neharot uevetoch biqot ma'yanot, I will open on the bare heights rivers and in the midst of the valleys springs.' The shefiim (bare heights = the naked rocky ridges of the desert, where no moisture would normally be found) receive rivers; the biqot (valleys/ravines) receive springs. 'I will turn the wilderness into a pool of water' (asim midbar le'agam-mayim = I will make the wilderness a pool of water) and 'dry ground into springs' (ve'erets tsiyah lemo'tse'ei mayim = the arid land into water-sources). The new-Exodus transformation: the barren Syro-Arabian desert that the returning exiles must cross becomes a well-watered garden. The imagery draws on the Exodus wilderness (Exod 17:6: water from the rock; Num 20:11: water from the rock again) but exceeds it: not just one miraculous spring but a landscape transformation.</p>",
    "19": "<p>'I will plant in the wilderness cedar, acacia, myrtle, and olive trees; I will set in the desert cypress, plane tree, and pine together' — the seven-tree oracle of new creation: 'eten bamidbar erez shittah vahadds veets shemen, I will give/plant in the wilderness cedar, acacia, myrtle, and oil-tree.' The seven trees: (1) erez = cedar (the prestige timber of Lebanon, used for temples and palaces); (2) shittah = acacia (the desert-adapted hardwood, used for the tabernacle: Exod 25-27); (3) hadac = myrtle (the fragrant evergreen bush of Palestinian hills, used in Sukkoth: Neh 8:15; Zech 1:8-11); (4) ets shemen = olive/oil-tree; (5) berosh = cypress; (6) tiddhar = plane tree (probably the elm or holm-oak); (7) te'ashshur = pine/box-tree. Seven trees = completeness. The planting in the wilderness where no trees grow = the reversal of curse (the barren wilderness as punishment for covenant-breaking becomes a garden through covenant-restoration). The acacia's inclusion specifically echoes the tabernacle — the new-Exodus includes a new place of divine dwelling.</p>",
    "20": "<p>'So that they may see and know, consider and understand together, that the hand of the LORD has done this, and the Holy One of Israel has created it' — the purpose clause for all the wilderness-transformation oracles: 'lema'an yiru veyede'u veyasimu veyaskillu yachdav, so that they may see and know and consider and understand together.' The four cognitive verbs (see, know, consider, understand = re'oh, yadah, sum, sakhal) = a comprehensive understanding that moves from empirical observation (see) through knowledge to reflection and wisdom. 'That the hand of the LORD has done this' (ki yad-YHWH asthah zot = for the hand of YHWH has done this) and 'the Holy One of Israel has created it' (veqedosh Yisrael bera'ah). The water and trees are signs designed to produce recognition of YHWH — the new Exodus is missionary: it is calibrated to produce universal 'seeing and knowing.' The double identification (YHWH's hand + the Holy One of Israel) appears throughout the Cyrus-oracle sections, insisting that the redemption is specifically Israel's covenant-God's act, not a general providence.</p>",
    "21": "<p>'Present your case, says the LORD; bring forward your strongest arguments, says the King of Jacob' — the divine court reconvenes after the Israel-comfort section (vv8-20): 'qarvu rivekhem yomar YHWH, bring near your case, says YHWH.' The riv (legal case/dispute = the technical term for the covenant lawsuit, the rib, appearing in Mic 6:1-2; Isa 1:18; Hos 4:1; Jer 2:9 as YHWH's legal dispute with Israel; here YHWH invites the idols' legal case). 'Bring forward your strongest arguments' (habiyu atsumotelkhem, bring your strongest proofs) = 'atstumot = the strongest, most powerful arguments. 'Says the King of Jacob' (yomar melek Ya'aqov) — YHWH's kingship over Jacob/Israel is the legal standing from which he adjudicates the case. The invitation is genuinely open: YHWH does not refuse the evidence of the idols but invites their best case.</p>",
    "22": "<p>'Let them come forward and tell us what will happen; let them declare the former things, what they were, so we may consider them and know their outcome; or announce to us what is to come' — the two-part test of true deity: prediction of the past and prediction of the future. (1) 'Let them declare the former things, what they were' (veharishonot mah hennah yaggidu = and the former things, what they are, let them tell) — can the idols explain the meaning of past history? The rishonut (former things = the historical events of the past, specifically the Exodus and the Assyrian crisis) as interpreted events: can the idols explain what YHWH has already done? (2) 'Or announce to us what is to come' (o haba'ot hashmi'unu = or the coming things, let them make us hear) — can they predict the future? The Babylonian divination system (astrology, hepatoscopy, extispicy) claimed to do exactly this. YHWH's courtroom challenge is to the entire Babylonian religious-intellectual system: can your methods actually predict what will happen?</p>",
    "23": "<p>'Tell us what is to come in the future, so that we may know you are gods. Do good or do evil — do something — so that we may see it and stand in awe together' — the challenge reaching its maximum: 'haggidu ha'atidot le'achor, tell us the things to come, for the future.' The desperate offer: 'asu-tov o-hare'u, do good or do evil.' The gods are invited to do anything at all — good or bad — just something observable and testable. 'So that we may see it and stand in awe together' (venire'eh venirad yachdav = and we will see and fear together) — the standard response to genuine divine action is fear (Gen 28:17: 'how awesome is this place'; Exod 14:31: 'Israel saw the great power of YHWH'). The idols cannot produce this fear because they cannot act. The challenge is ultimately performative: not doctrine but demonstration.</p>",
    "24": "<p>'See — you are nothing and your work amounts to nothing; whoever chooses you is an abomination' — the verdict against the idols: 'hen-attem me'ayin ufaalekhem me'afah, behold you are from nothing and your work from nothing.' The categorical verdict: the idols are not just weak but ontologically nothing (me'ayin = from the nothing of 40:17; me'afah = from the breath/nothing). 'Whoever chooses you is an abomination' (toevah yivchar bakhem = an abomination, whoever chooses you). The toa'evah (abomination = the strongest negative evaluative term in Hebrew, used for religious idolatry in Deut 7:25; 13:14; 17:1; 27:15 and for sexual ethics in Lev 18:22; 20:13; and for false weights in Prov 11:1). The choice of an idol is not merely unwise but abominable — the strongest possible condemnation. The verdict of the divine courtroom after a fair hearing in which the idols could not produce evidence.</p>",
    "25": "<p>'I have stirred up one from the north, and he comes; from the east he comes, calling on my name; he will trample rulers as if they were mortar, as a potter treads clay' — the Cyrus-oracle resumed: 'ha'iroti mitsafon vayato mimizrach-shemesh yiqra vishmi, I stirred up one from the north, and he came; from the rising of the sun he calls on my name.' The double direction: from the north (Cyrus's ally Media is north of Babylon) and from the east (Persia is east). 'Calling on my name' (yiqra vishmi = calls by my name) = Cyrus acknowledged YHWH in the Cyrus Cylinder (538 BCE), where he attributes his conquests to divine sanction, and in Ezra 1:2: 'the LORD, the God of heaven, has given me all the kingdoms of the earth.' 'He will trample rulers as if they were mortar' (veyavo saganim kemoh-homer = he will come on governors as if on clay) = the vivid image of boots trampling the clay of the battlefield. 'As a potter treads clay' (ukhmoh yotser yirmas-tit = as a potter treads the wet clay) — the same material transformed by Cyrus's feet from obstacle to raw material.</p>",
    "26": "<p>'Who declared this from the beginning, so we could know? Who foretold it beforehand, so we could say, He is right? Not one declared it; not one announced it; not one heard you say it' — the proof-from-prediction argument applied to Cyrus: 'mi-higgid mero'sh venede'ah, who declared from the beginning and we would know?' The retrospective question: which deity announced Cyrus before Cyrus appeared? The answer: 'en maggid, en mashmi'ah, en shome'a imroteikhem, no one declared, no one proclaimed, no one heard your words.' The triple negation: no declaration, no proclamation, no audience. The Babylonian diviners did not predict Cyrus; their extensive omen-literature and astrological system gave them no advance warning of the Persian conquest. Only YHWH predicted it — through Isaiah in the 8th century, naming Cyrus 150 years before his birth (44:28; 45:1).</p>",
    "27": "<p>'I was the first to say to Zion, Look — here they are! And I give Jerusalem a messenger of good news' — YHWH's self-identification as the first herald: 'rishon letsiyon hinneh hinnam, the first to Zion: behold, here they are!' YHWH himself is the first herald who announced to Zion that the return was coming — before any human messenger arrived. 'I give Jerusalem a messenger of good news' (veliYerushalayim mevasser etten = and to Jerusalem I give a bringer-of-good-news). The mevasser (herald of good news = the same root as the gospel, euangelion; cf. 40:9 where Zion/Jerusalem is the mevasser). Here YHWH gives the city a herald — the announcement of the return is YHWH's own first word to his city. The verse contrasts with the idol-diviners of v26 (who could say nothing) and YHWH who spoke first.</p>",
    "28": "<p>'For I looked, and there was no one; among them there was no counselor; when I asked them, not one could answer' — the divine inspection of the idol-assembly for a valid counselor: 've'ere ve'en ish, and I looked and there was no man.' YHWH surveyed the assembly of the nations' gods and their representatives and found: 'among them there was no counselor' (ume'eleh ein yo'ets = and from these there is no counselor). The yo'ets (counselor = the political-military advisor, the same term as the messianic title in 9:6: 'Wonderful Counselor'). 'When I asked them, not one could answer' (vesh'al otam vayyashivu davar = and I asked them and they returned a word) — the idols cannot answer divine inquiry. The comparison: the nations' gods have no counselors who can answer divine questioning; YHWH himself is the Wonderful Counselor (9:6) whose counsel is perfect (25:1: 'your counsel of old is faithful and true').</p>",
    "29": "<p>'See — they are all emptiness; their works come to nothing; their cast images are just wind and futility' — the final verdict of the divine courtroom over idols: 'hen kullam aven, behold they are all emptiness.' The aven (emptiness/trouble/iniquity = the comprehensive word for the worthlessness of idolatry; used in Hos 4:15 for Bethel; Amos 5:5 for the sanctuary at Gilgal: 'Beth-aven, house of wickedness'). 'Their works come to nothing' (ma'aseihem efes = their works are nothingness) — the same efes as 40:17 ('the nations are as nothing'). 'Their cast images are just wind and futility' (ruach vetohu nesikheihem = wind and chaos are their cast-images). The tohu (chaos = the Gen 1:2 pre-creation void) applied to the molten images — they have achieved the anti-creation. YHWH's work is creation; idol-worship is the return to chaos and nothingness.</p>"
  },
  "42": {
    "1": "<p>Isaiah 42:1 opens the First Servant Song (42:1-4), one of four Servant Songs in Second Isaiah (42:1-4; 49:1-6; 50:4-11; 52:13-53:12): 'hen avdi etmokh-bo, behold my servant, I uphold him.' Three characteristics of the Servant: (1) 'my servant, whom I uphold' (avdi ethmokh-bo = my servant, I hold/support him) — divine backing; (2) 'my chosen one, in whom I delight' (behiiri ratsethah nafshi = my chosen one, in whom my soul delights) — the same 'soul delights' as Gen 34:8 (Shechem's delight in Dinah), applied to YHWH's delight in the Servant; (3) 'I have placed my Spirit on him' (natati ruchi alaiv = I have put my Spirit on him) — equipping for ministry. The mission: 'mishpat laggoyim yotsi = justice to the nations he will bring forth.' The mishpat (justice/teaching/ordinance = the proper ordering of society according to YHWH's standard) brought to the nations (goyim = the gentile peoples). Matt 12:18-21 quotes vv1-4 for Jesus. The Servant is simultaneously Israel (the corporate servant of 41:8-9) and the individual who fulfills what Israel failed to do.</p>",
    "2": "<p>'He will not shout or raise his voice, or make himself heard in the streets' — the quietness of the Servant's method: 'lo yitssaq velo yissa velo yashmia bachuuts qolo, he will not cry out and not lift and not make heard in the street his voice.' The three negatives of public clamor (crying out, lifting the voice, making heard in the street) = the full repertoire of public proclamation typical of (1) ANE royal heralds announcing conquests, (2) military commanders issuing battle orders, (3) marketplace disputants, (4) prophets in the temple gates (Jer 7:2: 'stand in the gate of the LORD's house and proclaim there this word'). The Servant works without public clamor — the contrast with both the noise of Babylonian divine processions (where Bel and Nebo were carried through the streets with great fanfare, 46:1-2) and even with the style of earlier prophets. Matt 12:19 quotes this directly for Jesus's characteristic avoidance of public spectacle (Matt 12:15-16: 'warned them not to say who he was').</p>",
    "3": "<p>'A bruised reed he will not break, and a smoldering wick he will not snuff out; he will bring forth justice faithfully' — the Servant's treatment of the vulnerable: 'qaneh ratsuts lo yishbor ufishtat kehavah lo yekhabennah, a bruised reed he will not break, and a smoldering wick he will not extinguish.' Two images of extreme fragility: (1) qaneh ratsuts (bruised/cracked reed = a hollow river reed used as a musical instrument or writing tool that has been crushed or cracked — normally discarded as useless); (2) pishtat kehah (a dimly smoldering wick = the flax wick of an oil lamp that is barely burning, about to go out). The Servant's ministry preserves what human systems discard as non-functional. 'He will bring forth justice faithfully' (le'emet yotsi mishpat = in truth/faithfulness he will bring out justice) — the persistence of the justice-mission despite the gentleness of the method. Matt 12:20 applies this to Jesus's healing ministry: the bruised reed = the chronically ill, socially marginal, spiritually depleted people he healed rather than dismissed.</p>",
    "4": "<p>'He will not grow faint or be discouraged until he has established justice in the earth; and the coastlands will wait for his law' — the Servant's inexhaustibility and universal mission: 'lo yikheh velo yaruts, he will not grow faint and will not be crushed.' The precise inversion of the bruised reed and smoldering wick: the Servant himself will not be 'faint' (yikheh = the dim-wick word used in v3: kehah) nor 'crushed/broken' (yaruts = the same root as ratsuts of the bruised reed). He does not break the bruised reed because he himself does not break. He does not snuff out the smoldering wick because he himself is not snuffed out. 'Until he has established justice in the earth' (ad-yashim ba'arets mishpat = until he sets justice in the earth) — the temporal scope: the Servant persists until the task is complete. 'The coastlands will wait for his law' (vetor'atoh iyyim yeyahelu = and for his instruction the coastlands wait) — the universal expectation: the most distant peoples (coastlands = 40:15; 41:1, 5) are waiting for the Servant's teaching.</p>",
    "5": "<p>'This is what God the LORD says — he who created the heavens and stretched them out, who spread out the earth and everything it produces, who gives breath to the people on it and spirit to those who walk on it' — the Creator's formal speech introducing the Servant commission: 'ko-amar ha'El YHWH bore hashamayim venotehem, thus says the God YHWH, creator of the heavens and the one who stretched them out.' The fourfold Creator-resume before commissioning the Servant: (1) 'bore hashamayim = creator of the heavens'; (2) 'venotehem = who stretched them out' (the spatial expansion of creation); (3) 'roqa ha'arets vetsetsaeyha = who spread out the earth and its offspring/produce'; (4) 'noten neshama la'am aleyhah veruach laholkhim bah = giving breath to the people on it and spirit to those walking on it.' The neshama (breath = the divine breath of Gen 2:7: 'breathed into his nostrils the breath of life') given to all people — universal bestowal of life. The Servant is commissioned by the God who creates and sustains all life — his mission is therefore cosmic in scope.</p>",
    "6": "<p>'I, the LORD, have called you in righteousness; I will take hold of your hand and keep you; I will make you a covenant for the people, a light for the nations' — the Servant's commission: 'ani YHWH qeratikha vetsedek veachazzeq beyadekha, I, YHWH, have called you in righteousness and will grip your hand.' Three commissioning acts: (1) 'called you in righteousness' (qeratikha vetsedek = called you for the purpose of righteousness/covenant-justice); (2) 'take hold of your hand' (ve'etchazzeq beyadekha = I will hold firmly your hand, cf. 41:13: 'I hold your right hand') — divine physical support; (3) 'keep you' (ve'etsorkha = I will guard/preserve you). Two mission-roles: 'berit am = covenant for/of the people' (the Servant embodies or mediates the covenant between YHWH and Israel; the ambiguity is productive: he is both the content of the covenant and its mediator) and 'or goyim = light of the nations.' Luke 2:32 (Simeon): 'a light for revelation to the Gentiles, and the glory of your people Israel'; Acts 13:47 (Paul and Barnabas): 'I have made you a light for the Gentiles.'</p>",
    "7": "<p>'To open eyes that are blind, to bring prisoners out of the dungeon, to release from prison those who sit in darkness' — the practical content of the Servant's mission: 'lifqoach einayim ivrot, to open blind eyes.' Three liberating acts: (1) 'open eyes that are blind' (lefqoach einayim ivrot = to open blind eyes) — literal blindness and the spiritual blindness of 42:18-20; (2) 'bring prisoners out of the dungeon' (lehotsi mimmasgger asir = to bring out from the prison/dungeon the prisoner) — literal captives in Babylonian prisons and the exilic community as imprisoned; (3) 'release from prison those who sit in darkness' (mibeit kele yoshevei choshekh = from the house of imprisonment those sitting in darkness). The three-fold liberation = the comprehensive redemption from every form of captivity. Luke 4:18 (Jesus in Nazareth): 'he has sent me to proclaim freedom for the prisoners and recovery of sight for the blind' — quoting Isa 61:1-2 but echoing this passage. John 9:39: 'For judgment I have come into this world, so that the blind will see and those who see will become blind.'</p>",
    "8": "<p>'I am the LORD; that is my name; I will not give my glory to another nor my praise to carved idols' — the divine identity assertion and the grounds for the Servant's mission: 'ani YHWH hu shemi, I, YHWH, that is my name.' The hu shemi (that is my name) = the definitive identification, not merely a description but a declaration of essential identity. 'I will not give my glory to another' (khevodi le'acher lo etten, my glory to another I will not give) — the divine jealousy that grounds the Servant's exclusive commission: the Servant brings the nations to the knowledge of YHWH's glory, not to any other deity's glory. 'Nor my praise to carved idols' (utehillati lafssilim = and my praise to carved idols) — the worship that the nations currently give to idols must be redirected to YHWH. The Servant's mission is fundamentally doxological: oriented toward the universal praise of the one true God.</p>",
    "9": "<p>'See — the former things have come to pass, and new things I now declare; before they spring up I announce them to you' — the hermeneutic principle of Second Isaiah: 'harishonut hineh bau, the former things, behold they have come to pass.' The rishonut (former things = the earlier events of salvation history: Exodus, wilderness, conquest, Davidic kingdom, Assyrian crisis) have 'come to pass' (bau = they have come/happened = they are verified history). 'And new things I now declare' (vachadashot ani maggid = and new things I am announcing) = the hadashot (new things = the new Exodus from Babylon, the Servant's mission, the universal salvation) now being announced. 'Before they spring up I announce them to you' (biterem titsmachnah ashmi'a etkhem = before they sprout I let you hear them) — the prophetic word as advance announcement: YHWH speaks before the event springs up from the ground like new vegetation. The prediction-announcement pattern is YHWH's trademark (41:22-23: the challenge to the idols to predict; 41:26: 'who declared this from the beginning?').</p>",
    "10": "<p>'Sing to the LORD a new song, his praise from the ends of the earth — you who sail the sea and all its creatures, you coastlands and their inhabitants' — the new-song call: 'shiru laYHWH shir chadash, sing to YHWH a new song.' The shir chadash (new song = the song that matches a new act of salvation; Ps 33:3; 40:3; 96:1; 98:1; 144:9; 149:1; Rev 5:9; 14:3) is demanded because YHWH is doing a new thing (42:9; 43:19). 'His praise from the ends of the earth' (tehillato miqtseh ha'arets = his praise from the end of the earth) — the geographic scope: the new song arises universally, not just from Jerusalem's temple. The choir: 'you who sail the sea' (yoredei hayam = those who go down to the sea = sailors/maritime traders; Ps 107:23), 'all its creatures' (umelo'o = and all its fullness = the marine life; Ps 96:11: 'let the sea resound and all that is in it'), 'you coastlands and their inhabitants' (iyyim veyosheveiyhem = the distant islands/coastlands and their inhabitants). The maritime trade-world as the first universal choir.</p>",
    "11": "<p>'Let the wilderness and its towns raise their voice, the villages where Kedar dwells; let the inhabitants of Sela sing for joy; let them shout from the tops of the mountains' — the desert-world's choir: 'yiseu midbar ve'araiv chatserim, let the wilderness and its cities lift up their voices.' The contrast with v10's maritime world: now the desert peoples join. 'The villages where Kedar dwells' (chatserim teshev Qedar = the unwalled settlements where Kedar dwells) — Kedar (from Gen 25:13, a son of Ishmael = the Arab tribal confederation of the north Arabian desert, known for their black tents, Ps 120:5: 'I dwell in the tents of Kedar'; Song 1:5: 'I am dark but lovely... like the tents of Kedar'). 'The inhabitants of Sela' (yoshevei sela = the inhabitants of the Rock = possibly Petra, the Nabataean capital in Edom, or a reference to rocky highlands generally). The desert peoples — nomadic Arabs and rock-dwellers — join the maritime peoples in the universal new song.</p>",
    "12": "<p>'Let them ascribe glory to the LORD and proclaim his praise in the coastlands' — the doxological goal of the universal choir: 'yassimu laYHWH kavod vetehillato ba'iyyim yaggidu, let them ascribe to YHWH glory and his praise in the coastlands let them tell.' The kavod (glory = the weighty presence and honor due to YHWH; 40:5: 'the glory of the LORD will be revealed and all flesh will see it together') ascribed universally. The 'coastlands' (iyyim) appear for the fourth time in ch.42 (vv4, 10, 12) = the representative of the most distant, most 'other' people who are nevertheless included in the praise. The universal praise is not accidental but the designed outcome of the Servant's mission (42:6-7) and the new things YHWH is doing (42:9). The doxological purpose-statement of creation (43:7: 'I created for my glory') realized in the universal choir.</p>",
    "13": "<p>'The LORD marches out like a warrior, like a man of war he arouses his zeal; he cries out, he shouts aloud, he shows himself mighty against his enemies' — the divine warrior's battle-march: 'YHWH keggibbor yetse, YHWH goes out like a warrior.' The gibbor (mighty warrior/champion = the strongest and most elite fighting man; Gen 6:4: the 'Nephilim were the heroes/gibbor of old'; 2 Sam 23:8-39: David's thirty mighty warriors). 'Like a man of war he arouses his zeal' (keish milchamot ya'ir qin'ah = like a man of wars he arouses/stirs up his jealousy). The qin'ah (zeal/jealousy = the passionate, exclusive commitment of a covenant partner; 37:32: 'the zeal of YHWH of hosts will accomplish this'). 'He cries out, he shouts aloud' (yariya af-yatsriyach = he cries out, he also shouts/yells) — the battle cry of the divine warrior. The contrast with the quiet Servant (42:2: 'he will not shout or raise his voice') is held in tension: the Servant works quietly; YHWH the warrior acts loudly. Both are aspects of one redemptive plan.</p>",
    "14": "<p>'For a long time I have kept silent; I have been still and held myself back; now I will cry out like a woman in labor; I will gasp and pant' — the divine patience breaking into action: 'me'olam hecherasheiti achrish et'apaq, from long ago I have kept silent, I have been still and held back.' The me'olam (from long ago/eternity) of YHWH's restraint = the entire period of the Babylonian exile (and before it, the Assyrian period) during which YHWH appeared silent. 'Now I will cry out like a woman in labor' (keyyoleydah eph'ah, like a woman giving birth I will groan/gasp) — the childbirth metaphor for YHWH's action: not the composed sovereign but the groaning woman in the final stages of labor. The imagery is stunning in its vulnerability: YHWH's powerful act of salvation is compared to the involuntary, pain-driven gasp of a woman delivering a child. 'I will gasp and pant' (esh'af ve'eshom = I will inhale and exhale rapidly) — the panting of extreme exertion. The new creation that YHWH is about to accomplish is as costly and involuntary (from the perspective of the divine love) as childbirth.</p>",
    "15": "<p>'I will lay waste mountains and hills and dry up all their vegetation; I will turn rivers into dry land and drain the pools' — the new-Exodus geography inverted: 'achorev harim ugivot vekhol-esevam avish, I will devastate mountains and hills and dry up all their vegetation.' The reversal of ch.40's creation-imagery (40:4: 'every mountain and hill leveled') continues: now YHWH also dries the rivers and pools (v15) while elsewhere creating new rivers (41:18). The apparently contradictory images (drying rivers in 42:15 vs. creating rivers in 41:18; 43:19-20) reflect different landscapes: the obstacle-landscape of the enemies is dried and flattened; the route of the returning exiles is watered and smoothed. 'I will turn rivers into dry land and drain the pools' (asim neharot le'iyyim ve'agammim ovish = I will make rivers into dry land and pools I will dry up) — the drying of Babylon's waterways (the Euphrates and the irrigation canals) is exactly what Cyrus did when he diverted the Euphrates to allow his troops to enter Babylon (Herodotus 1.189-191).</p>",
    "16": "<p>'I will lead the blind along a road they have not known; I will guide them on paths they have never walked. I will turn darkness into light before them, and rough terrain into level ground. These are the things I will do, and I will not abandon them' — the promise to the blind exiles: 'veholakhti ivrim bederekh lo yada'u, and I will lead the blind on a road they have not known.' The 'blind' (ivrim = blind people = the exiles who cannot see the path of return, a development of the blind-servant imagery of 42:18-19, but here YHWH leads them rather than leaving them in blindness). 'Paths they have never walked' (binetivot lo yede'um adrikhem = on paths they do not know I will lead them) — the unknown terrain of the return from Babylon = the long desert route through the Syrian desert. Four transformations: (1) darkness → light; (2) rough terrain → level ground; (3) these actions are guaranteed; (4) 'I will not abandon them' (lo azavtim = I will not forsake them — the ultimate covenant promise of Deut 31:6: 'he will never leave you nor forsake you').</p>",
    "17": "<p>'Those who trust in carved idols and say to cast images, You are our gods, will be turned back and completely disgraced' — the contra-promise for idol-worshipers: 'nessugu achor yevoshu voshet, they will be turned back, they will be utterly shamed.' The contrast with Israel led forward (v16) and enemies turned back (41:11): those who trust idols will experience the shame-reversal that idols cannot prevent. 'Those who trust in carved idols' (habbot'im bappesel = those who trust in the carved image) — the use of batach (to trust/rely on) in its wrong direction: 30:12 indicted Judah for batach on Egypt; here the idol-worshipers batach on their manufactured deities. 'Say to cast images, You are our gods' (ha'omerim lemassekha attem elohenu = who say to the molten image: you are our gods) — the verbal declaration of the idol-worshipers as their act of religious confession, parallel to Israel's 'YHWH is our God' (Deut 6:4).</p>",
    "18": "<p>'Hear, you deaf! Look, you blind, and see!' — the prophetic summons to Israel's spiritual blindness and deafness: 'hashshi'um ureshmaou haivrim habitu lir'ot, hear, you deaf! Look, you blind, and see!' The sharp command (shim'u = hear! and habitu = look/gaze intently = the same imperative used in 40:26: 'lift up your eyes') addressed to those who are already deaf and blind. The double imperative to the disabled = the paradox of prophetic summons: calling the spiritually incapacitated to use the very faculties that are impaired. The irony: just after YHWH promised to lead the blind (v16) and to open blind eyes through the Servant (42:7), he turns to confront Israel's actual blindness. The blind exiles who need leading are also the blind Israel who refuses to see what YHWH is doing.</p>",
    "19": "<p>'Who is blind but my servant, or deaf like my messenger whom I send? Who is blind as my dedicated one, or blind as the servant of the LORD?' — the paradox of the blind Servant: 'mi iver ki im-avdi, who is blind but my servant?' The four designations of the same figure: (1) avdi = my servant; (2) malaki asher eshlag = my messenger whom I send; (3) meshullam = my dedicated/completed one (from shalem = complete, possibly 'the one at peace with YHWH' or 'the one given in exchange'); (4) eved YHWH = the servant of YHWH. All four are 'blind.' This is the paradox that many interpreters resolve by seeing two 'servants' in Isaiah: the individual Servant of 42:1-4 (who is not blind) and the corporate servant Israel (which is blind). The corporate servant Israel was commissioned to bring light to nations (42:6-7) but cannot see YHWH's acts. The blindness of Israel despite divine commission is the diagnosis that necessitates the individual Servant who is not blind.</p>",
    "20": "<p>'He sees many things but does not take them in; his ears are open but he does not hear' — the diagnosis of the blind servant's condition: 'ra'ot rabbbot velo tishmor paqoach oznayim velo yishma, seeing many things and not observing; opening ears and not hearing.' The two clauses are precisely parallel: (1) 'sees many things' (ra'ot rabbbot) but 'does not observe/guard' (velo tishmor = does not take notice, does not keep/heed = from shamar = to keep, watch, observe; the same root as keeping Torah) — Israel saw YHWH's historical acts (the Exodus, the Assyrian crisis, the Babylonian exile) but did not integrate them as evidence of YHWH's character; (2) 'ears are open' (paqoach oznayim = open ears) but 'does not hear' (velo yishma = does not hear with understanding) — physical hearing without spiritual comprehension. The diagnosis is not ignorance (they saw and heard plenty) but refusal of application.</p>",
    "21": "<p>'It pleased the LORD, for the sake of his righteousness, to make his law great and glorious' — the divine purpose frustrated by Israel's blindness: 'YHWH chafetz lema'an tsidqo, YHWH was pleased, for the sake of his righteousness.' YHWH's purpose: 'yagdil torah veyaadir = to make the Torah great and glorious/magnificent.' The gadal (to magnify/make great) and adar (to make glorious/magnificent) applied to the Torah = the divine intention that the Torah would be Israel's glory before the nations (Deut 4:6-8: 'this is your wisdom and understanding in the sight of the nations, who will hear about all these decrees and say, \"Surely this great nation is a wise and understanding people\"'). The irony: YHWH's glorious intention for the Torah is frustrated by Israel's blindness and deafness. The Torah designed to reveal YHWH's wisdom to the nations is not fulfilling its purpose because Israel is not living it.</p>",
    "22": "<p>'But this is a people robbed and plundered; they are all trapped in holes and hidden in dungeons; they have been made prey and there is no one to rescue them, made spoil and no one says, Give them back' — the condition of the blind servant-people: 'vehu am-shassui vevaluz, and this is a people robbed and plundered.' The graphic inventory of captivity: (1) 'shassui = robbed' (stripped of possessions); (2) 'vavaluz = plundered' (spoiled of everything); (3) 'trapped in holes' (bahadurim kulam pehuim = in holes all of them are snared); (4) 'hidden in dungeons' (ubettei kela'im hochba'u = and in prison-houses they are hidden); (5) 'made prey' (hayyu lavaz = they have become plunder); (6) 'made spoil' (ulashalal = and as spoil). Six conditions of total captivity. 'No one to rescue' (ve'ein matsil = and there is no one to deliver) and 'no one says, Give them back' (ve'ein omer hashev = and no one says: return them). The condition is both physical (Babylonian captivity) and political (no great power advocates for Israel's release).</p>",
    "23": "<p>'Who among you will pay attention to this? Who will listen and hear for what is to come?' — the prophetic summons to awareness: 'mi vakhem ya'azin zot yaqshiv veyishma le'achor, who among you will pay attention to this? Who will listen and hear for the future?' The mi (who = the rhetorical challenge to find even one person in Israel who will genuinely attend to the prophetic word). The 'pay attention' (ya'azin = to give ear/incline the ear = intensive hearing, the formal call of Deut 32:1: 'give ear, O heavens, and I will speak') and 'hear for the future' (yishma le'achor = hear for what comes after) = understanding the historical moment in light of what is coming. The question is not rhetorical in the sense of expecting no answer: it genuinely asks if anyone in the community is awake to the significance of the exile as YHWH's act.</p>",
    "24": "<p>'Who handed Jacob over to plunderers, and Israel to robbers? Was it not the LORD, against whom we have sinned? For they refused to walk in his ways and were not obedient to his law' — the theological answer to Israel's condition: 'mi natan lemeshishah Ya'aqov, who gave Jacob as plunder?' The question answered immediately: 'halo YHWH zu chatanu lo, was it not YHWH, against whom we have sinned?' The self-incrimination: Israel's captivity is not Babylon's achievement but YHWH's judgment. The grounding: 'velo avah bidrakhav halokh velo shame'u betorato, for they refused to walk in his ways and did not listen to his law.' The 'refusing' (lo avah = not willing, a strong volitional rejection; cf. Exod 7:14: 'Pharaoh's heart is hard; he refuses to let the people go') and 'not listening' (velo shame'u = they did not obey/hear the Torah). The exile is traced to two specific failures: (1) refusing to walk in YHWH's ways (covenant lifestyle); (2) not listening to the Torah (covenant law). Deuteronomy 28-30's exile-theology fulfilled.</p>",
    "25": "<p>'So he poured his burning anger and the force of battle upon him; it set him ablaze all around, but he did not understand; it burned him, but he took no notice' — the divine judgment and Israel's obtuseness: 'vayishpokh alaiv chema apo ve'ezuz milchamah, and he poured out on him his burning anger and the strength of battle.' The shafakh (pour out = the pouring of wine, water, or blood; Ps 79:6: 'pour out your wrath on the nations'; Jer 10:25: 'pour out your wrath on the peoples who do not know you') of chema apo (the burning anger = the fierce, heat-like anger of YHWH). 'It set him ablaze all around' (vatelabbehu missaviv = and it set him on fire all around) — the Babylonian destruction of Jerusalem as divine fire (Lam 2:3-4: 'he has set Zion on fire like a flaming fire'). The devastating punchline: 'but he did not understand' (velo yada = and he did not know) and 'it burned him, but he took no notice' (vattivhar-bo velo yasim al-lev = it burned him and he did not lay it on his heart). The exile itself — the most extreme divine act of discipline — did not produce understanding in Israel.</p>"
  },
  "43": {
    "1": "<p>Isaiah 43:1 pivots from judgment (42:24-25) to comfort with the 'but now' formula: 'veat'ah ko-amar YHWH bore'akha Ya'aqov veyotsrekha Yisrael, but now, thus says YHWH your creator, Jacob, and your former, Israel.' The double creative act: bore (created = the bara of Gen 1, the out-of-nothing creation) and yotser (formed = the yatsar of Gen 2:7, the clay-molding of the human body) — both creation-verbs applied to Israel's national formation. The reversal of 42:24-25's judgment: despite the burning, YHWH's creative relationship with Israel continues. 'Do not be afraid, for I have redeemed you' (al-tira ki ge'altikhah = do not fear, for I have redeemed you) — the go'el-action as completed past (ge'altikhah = perfect tense, I have already redeemed you) even before the exile ends. 'I have called you by name — you are mine' (qarati beshmekha li-attah = I called by your name, you are mine). The name-calling = intimate personal knowledge (Exod 33:12: 'I know you by name'; John 10:3: 'the shepherd calls his own sheep by name') and the covenant declaration: 'you are mine' (li-attah = to me you belong).</p>",
    "2": "<p>'When you pass through the waters, I will be with you; through the rivers, they will not overwhelm you. When you walk through the fire, you will not be scorched; the flame will not set you ablaze' — the four-element promise of divine presence in the midst of danger: 'ki-ta'avor bamayim itti-ani, when you pass through the waters, I will be with you.' The key word is 'through' (b- = in/through, not 'around'): the promise is not protection from the danger but presence within it. The waters and rivers = the Red Sea (the Exodus archetype, Exod 14) and possibly the Jordan (Josh 3). The fire and flame = possibly the furnace of Dan 3 (Shadrach, Meshach, Abednego), or the general image of severe trial by fire. All four elements (water, rivers, fire, flame) = the full spectrum of destructive natural forces as figures for the trials of exile and the journey home. 'They will not overwhelm you' (velo yishtefukhah = will not flood/overwhelm you; shataph = to overflow, Exod 15:10: 'the sea covered them') and 'will not set you ablaze' (velo-tivaar bekha = will not burn on you). The promise is not immunity but accompaniment.</p>",
    "3": "<p>'For I am the LORD your God, the Holy One of Israel, your Savior. I give Egypt as your ransom, Ethiopia and Seba in your place' — the theological ground of the promise: 'ki ani YHWH Elohekha qedosh Yisrael moshi'ekha, for I, YHWH your God, the Holy One of Israel, your Savior.' Three titles: YHWH (covenant name), qedosh Yisrael (Holy One of Israel = Isaiah's distinctive title, appearing 12x in chs.40-55), moshi'ekha (your Savior = from yasha = to deliver/save; cf. 43:11: 'there is no savior apart from me'). The ransom: 'natati khefer Mitsrayim Kush uSeva tachtekha, I give Egypt as your ransom, Cush and Seba in your place.' The theological interpretation of Persian history: Cyrus who liberated Israel (539 BCE) later conquered Egypt through his son Cambyses (525 BCE). The geopolitical price of Israel's liberation was Egypt's domination. The hefker (ransom = the payment that cancels a debt or redeems a captive; Exod 21:30) is YHWH's term for the geopolitical exchange: Egypt exchanged for Israel.</p>",
    "4": "<p>'Because you are precious in my eyes and honored, and because I love you, I will give people in exchange for you, nations in place of your life' — the divine love declaration: 'me'asher yaqart ve'einai nikhbadta va'ani ahavtikhah, because you are precious in my eyes and honored, and I love you.' The three terms of divine valuation: (1) yaqart (you are precious/costly = from yaqar = to be precious, rare, of great price; Ps 72:14: 'precious is their blood in his sight'); (2) nikhbadta (you are honored = from kavad = to be weighty, glorious, honored — the kavod-root); (3) ahavtikhah (I love you = the explicit declaration of divine love). The divine 'I love you' addressed to the corporate Israel is rare in OT prophecy (Mal 1:2: 'I have loved you says the LORD'; Jer 31:3: 'I have loved you with an everlasting love'). The love as the motivation for the ransom: YHWH gave Egypt because he loves Israel. 'I will give people in exchange for you, nations in place of your life' (ve'eten adam tachtekhah ule'ummim tachat nafshekha = I give a man/people in your stead and nations in exchange for your life).</p>",
    "5": "<p>'Do not be afraid, for I am with you. I will bring your offspring from the east and gather you from the west' — the ingathering from east and west: 'al-tira ki-imkha-ani, do not be afraid, for I am with you.' The fifth occurrence of the 'do not fear' formula in chs.41-43, each one expanding the grounds for confidence. 'I will bring your offspring from the east' (mimmizrach avi zar'ekha, from the east I will bring your offspring/seed) and 'gather you from the west' (umimma'arav aqabbetstsekhah = from the west I will gather you). The ingathering of the Diaspora from multiple directions was partially fulfilled in the return under Zerubbabel (Ezra 1-2), Ezra (Ezra 7-10), and Nehemiah (Neh 1-7), and fully anticipated in the eschatological ingathering (Matt 24:31: 'he will send his angels with a loud trumpet call, and they will gather his elect from the four winds'; Rev 7:9: 'a great multitude that no one could count, from every nation').</p>",
    "6": "<p>'I will say to the north, Give them back! and to the south, Do not hold them back. Bring my sons from far away, my daughters from the ends of the earth' — the four-directional ingathering: 'omar latsafon teni ueladdrom al-tikh'ali, I will say to the north: give back! and to the south: do not withhold!' The north and south (adding to the east and west of v5) = all four directions = the complete dispersion of the Diaspora gathered from every compass point. 'Bring my sons from far away, my daughters from the ends of the earth' (havi'i vanai merachok uvnotai miqtseh ha'arets = bring my sons from far away and my daughters from the end of the earth) — the gender-inclusive ingathering: sons and daughters, not merely male warriors or adult males. The family-gathering language: 'my sons' (vanai = my sons, YHWH's children in the covenant-family sense of Exod 4:22: 'Israel is my firstborn son') and 'my daughters' (uvnotai = and my daughters) = all of Israel as YHWH's children.</p>",
    "7": "<p>'Everyone who bears my name, whom I created for my glory, whom I formed and made' — the identity-criterion for the ingathering: 'kol hanniqra vishmi, everyone who is called by my name.' The criterion is not ethnic purity or location but the divine name-bearing (cf. Num 6:27: 'so they will put my name on the Israelites, and I will bless them'; Deut 28:10: 'then all the peoples of the earth will see that you are called by the name of the LORD'). Three creation-verbs: (1) 'whom I created' (bera'tiiv = I created him, the bara of Gen 1); (2) 'formed' (yetsartiiv = I formed him, the yatsar of Gen 2:7); (3) 'made' (va'assitiiv = and I made him, the asah of Gen 1:26-27). The triple creation = the comprehensive divine investment in this people. The purpose: 'likevodi bera'tiiv = for my glory I created him' — existence for doxological purpose (cf. 42:12: 'ascribe glory to the LORD').</p>",
    "8": "<p>'Bring out the people who are blind — though they have eyes — and those who are deaf — though they have ears!' — the paradox of the blind witnesses: 'hotssi am-iver ve'einayim yesh vecheresh ve'oznayim lo, bring out the people who are blind, yet have eyes; and deaf, yet have ears.' The am-iver (blind people = the corporate servant-Israel of 42:18-20 who could not see YHWH's acts) are now summoned as witnesses to the divine courtroom. The qualification 've'einayim yesh = yet having eyes' = they are not organically blind (no physical eyes), they are functionally blind (spiritual blindness despite physical sight). The same paradox applied to deafness. The irony: the witnesses called to testify to YHWH's uniqueness are people who have been unable to perceive YHWH's acts — yet their very existence (as a people who have been preserved despite exile) is itself the testimony. Their corporate survival is the evidence, even if they cannot articulate it.</p>",
    "9": "<p>'Let all the nations gather together; let the peoples assemble. Who among them declared this, or foretold us what has happened before? Let them bring their witnesses to prove themselves right — or let them hear and say, It is true' — the divine courtroom (cf. 41:1, 21-29) reconvened with both Israel and the nations: 'kol-haggoyim niqbetsu yachdav veyease'afu le'ummim, all the nations gathered together and the peoples assembled.' The comprehensive assembly: all nations (kol-haggoyim) and all peoples (le'ummim). The dual evidentiary challenge: (1) 'Who among them declared this, or foretold what has happened before?' (mi vahem yaggid zot verishonut yashmie'enu = who among them declares this and the former things announces to us) — the prediction test of 41:22-23; (2) 'Let them bring their witnesses to prove themselves right' (yittenu eideihem veyitsdaqu = let them bring their witnesses so they may be declared right) — legal witnesses for the idols' case. 'Or let them hear and say, It is true' (veyishme'u veyo'meru emet = or let them hear and say: truth) — even the option of simply agreeing with YHWH is offered.</p>",
    "10": "<p>'You are my witnesses, declares the LORD, along with my servant whom I have chosen — so that you may know and believe me and understand that I am the one. Before me no god was formed, and after me there will be none' — Israel's designation as YHWH's witnesses: 'attem edai ne'um-YHWH, you are my witnesses, declares YHWH.' The Israel brought as blind witnesses (v8) is now commissioned as YHWH's witnesses. Along with 'my servant whom I have chosen' (avdi asher bechharti = my servant whom I have chosen = the individual Servant of 42:1 who knows and sees, providing what the blind-Israel cannot). The purpose: 'lema'an tede'u veta'aminu li vehavinu ki-ani hu = so that you may know and believe/trust me and understand that I am he.' The three levels of knowledge: (1) yada (know = experiential knowledge); (2) aman (believe/trust = the same root as amen = reliable, settled confidence); (3) bin (understand = comprehensive insight). 'Before me no god was formed, and after me there will be none' (lifanai lo-notsar El ve'acharai lo yihyeh = before me no god was formed and after me there will not be) — the absolute monotheism expressed as temporal exclusivity.</p>",
    "11": "<p>'I, I am the LORD, and apart from me there is no savior' — the emphatic monotheistic exclusivity: 'anoki anoki YHWH ve'en mibbal'adai moshi'a, I, I, YHWH, and there is no savior apart from me.' The doubled first-person pronoun (anoki anoki = I, I) = the highest possible emphasis in Hebrew (cf. v25: 'I, I am the one who blots out your transgressions'). The 'apart from me' (mibbal'adai = away from me/except through me) qualifier: not 'I am better than other saviors' but 'there is no other in the savior-category.' The en moshi'a (there is no savior) is an ontological claim, not merely a comparative boast. The Babylonian gods were identified as 'saviors' in their texts — Marduk saved Babylon from Tiamat, Bel protected the nation. YHWH's claim denies not their power but their existence as a category.</p>",
    "12": "<p>'I declared, I saved, and I proclaimed — when there was no foreign god among you. You are my witnesses, declares the LORD, and I am God' — YHWH's historical track record as the ground of the witness-testimony: 'ani higgadti vehoshi'ati vehishma'ti, I declared and saved and proclaimed.' The three-stage testimony: (1) higgadti (I declared/announced = the prophetic prediction before the event); (2) hoshi'ati (I saved = the historical act of deliverance); (3) vehishma'ti (I proclaimed/made heard = the testimony after the event). 'When there was no foreign god among you' (ve'en bakhem zar = and there was no strange/foreign among you) = a reminder that during the Exodus and conquest, Israel was not contaminated by foreign religious systems — the purity of YHWH's relationship with early Israel as the baseline. 'You are my witnesses, declares the LORD, and I am God' (attem edai ne'um-YHWH va'ani El = you are my witnesses, declares YHWH, and I am God) — the commissioning formula repeated, now with the simple and absolute 'I am God' (va'ani El).</p>",
    "13": "<p>'Even from eternity I am he. No one can deliver from my hand. When I act, who can reverse it?' — YHWH's eternal, irresistible sovereignty: 'af-meyom ani hu, even from the beginning of the day I am he.' The meyom (from the day = from the beginning of time/eternity = the 'day' as the start of created time) — YHWH's existence predating the created order. 'No one can deliver from my hand' (ve'en miyyadi matsil = and there is no one from my hand who delivers) — the absolute scope of divine sovereignty: no other power can override YHWH's acts or rescue those whom YHWH holds. 'When I act, who can reverse it?' (ef'al umi yeshivenah = I will act and who will turn it back?) — the irresistibility of divine purpose. The three claims (eternal being, inescapable power, irreversible action) form a complete sovereignty-statement that is simultaneously comfort (for Israel) and judgment (for Babylon).</p>",
    "14": "<p>'This is what the LORD says — your Redeemer, the Holy One of Israel: For your sake I am sending against Babylon and will bring down all of them as fugitives — even the Chaldeans — in the ships that were once their pride' — the specific Babylon-judgment oracle: 'ko-amar YHWH go'alekhem qedosh Yisrael, thus says YHWH your redeemer, the Holy One of Israel.' The twofold divine title (Go'el + Holy One of Israel) anchors the judgment in covenant-redemption. 'For your sake I am sending against Babylon' (lema'ankhem shillachti Babelah = for your sake I have sent to Babylon) — the motivation: Israel's redemption motivates the Babylon-judgment. 'And will bring down all of them as fugitives' (vehoradti varikhim kullam = and I will bring down all of them as fugitives/ones who flee). 'Even the Chaldeans, in the ships that were once their pride' (veKhasdim be'oniyot rinnatam = and the Chaldeans in the ships of their shouting/cry of joy). The Chaldeans (the ruling class of Babylon) who had fleets on the Euphrates and Persian Gulf — their ships of pride become ships of flight. The proud Babylonian maritime commerce reversed into a means of humiliating escape.</p>",
    "15": "<p>'I am the LORD, your Holy One, Israel's Creator, your King' — the fourfold divine self-identification: 'ani YHWH qedoshshekhem bore Yisrael malkekkhem, I, YHWH, your Holy One, creator of Israel, your King.' The four titles: (1) YHWH (covenant name); (2) qedoshshekhem (your Holy One = the personal possession of the holy title); (3) bore Yisrael (creator of Israel = echoing 43:1 and connecting the creation-theology to the kingship); (4) malkekkhem (your King = the divine kingship over Israel, announced in 33:22: 'YHWH is our king; it is he who will save us'). The divine King who created Israel is the same one who is about to defeat Babylon — the personal-national-cosmic scale of YHWH's lordship compressed into a four-word identity statement.</p>",
    "16": "<p>'This is what the LORD says — he who makes a way through the sea and a path through the mighty waters' — the Exodus-credential introduction: 'ko-amar YHWH hannoten bayyam derekh, thus says YHWH who makes/gives in the sea a way.' The Exodus reference: the crossing of the Red Sea (Exod 14:21-22: 'Moses stretched out his hand over the sea, and all that night the LORD drove the sea back with a strong east wind... the waters were divided'). 'A path through the mighty waters' (uvemayim azzim netivah = and in the mighty waters a path/path-way). The natib (path = a narrow, rarely traveled way through difficult terrain) in the 'mighty waters' (mayim azzim = strong, powerful waters) = the passage through the Red Sea as a narrow path through impossible terrain. This credential introduces the oracle of v17 before YHWH claims something even greater (the new thing of v19) that supersedes even this Exodus miracle.</p>",
    "17": "<p>'Who brought out chariot and horse, army and warrior together — they lay down and could not rise; they were extinguished, quenched like a wick' — the completion of the Exodus reference: 'hammotsi rekhev-wasussus chayil va'izuz yachdav, who brings out chariot and horse, army and warrior together.' The four military elements of Pharaoh's pursuing army: rekhev (chariot), sussus (horse), chayil (army/force), ve'izuz (and warrior/mighty one) — all of them together (yachdav). The result: 'yishkavu bal-yaqumu do'aku khappishtah kammu, they lay down and could not rise; they were extinguished like a wick.' The kammu (like a wick = the wick of the oil lamp, which is extinguished by pinching) recalls 42:3's 'smoldering wick he will not snuff out' — the Servant does not extinguish the barely-burning wick of the vulnerable; but YHWH does extinguish Pharaoh's army 'like a wick.' The irony: the Egyptian army, which seemed as inexorable as the mighty waters, was extinguished as easily as a lamp-flame.</p>",
    "18": "<p>'Do not remember the former things, or consider the events of long ago' — the startling command to forget the Exodus: 'al-tizkeru rishonut, do not remember the former things.' The rishonut (former things = the same term as 42:9's 'former things have come to pass') = the Exodus, the wilderness, the conquest — the paradigmatic salvation events that Isaiah has been citing as credentials (41:17-20; 42:14-16; 43:16-17). 'Or consider the events of long ago' (vequdemiyot al-titevanenu = and the things of old, do not contemplate). This command is shocking given the entire theology of Deuteronomy (Deut 5:15: 'remember that you were slaves in Egypt'; 8:2: 'remember how the LORD your God led you through the wilderness') where the Exodus-memory is the primary theological ground for obedience. The command here is not to forget the Exodus entirely but to not allow past salvation to limit expectation of future salvation — the new thing is so much greater that comparing it to the Exodus is inadequate.</p>",
    "19": "<p>'Look — I am doing something new; even now it springs up. Do you not see it? I am making a way in the wilderness and rivers in the desert' — the 'new thing' oracle: 'hineni oseh chadashah attah titsmach halo tede'uha = behold I am doing a new thing; now it springs up — do you not know it?' The chadashah (new thing = the feminine adjective for 'new,' the hadashot of 42:9) springing up like new vegetation from the ground (titsmach = present tense: it is already sprouting; the new exodus has already begun in the divine plan even before it is visible). 'I am making a way in the wilderness and rivers in the desert' (asim bamidbar derekh bishimon neharot = I am setting in the wilderness a way, in the wasteland rivers). The wilderness way and desert rivers invert both the Exodus ('a way through the sea,' v16) and the wilderness experience (where there was no water without miracle) — the new Exodus will not need the Red Sea path; the desert itself becomes a highway with rivers alongside. The return from Babylon is the historical fulfillment; the eschatological return (Rev 22:1-2: 'the river of the water of life') is the ultimate one.</p>",
    "20": "<p>'The wild animals will honor me — the jackals and the ostriches — because I provide water in the wilderness and rivers in the desert, to give drink to my chosen people' — the non-human creation joining the praise: 'tekabbedbani chayat hassadeh tanniyim uvenot ya'anah, the creatures of the field will honor me — the jackals and the ostriches.' The tan (jackals = the howling scavengers of the desert and ruined cities; Isa 34:13; 35:7; Jer 9:11) and benot ya'anah (ostriches = literally 'daughters of the owl/howl,' the large flightless bird of the desert) = the most desolate desert creatures. Even they honor YHWH because the desert water benefits them: 'for I provide water in the wilderness and rivers in the desert' (ki natati vamidbar mayim neharot bishimon = for I give in the wilderness water, rivers in the wasteland). 'To give drink to my chosen people' (leshaqot ami bechiiri = to give drink to my people, my chosen one). The animals benefit collaterally from the grace extended to Israel — the restoration of Israel restores the whole creation (Rom 8:19-22: 'the creation waits in eager expectation for the children of God to be revealed').</p>",
    "21": "<p>'The people I formed for myself, that they might declare my praise' — the purpose-statement of Israel's existence: 'am-zu yatsarti li tehillati yesapperu, this people I formed for myself — my praise they will tell.' The yatsarti (I formed = the potter's forming, Gen 2:7; 43:1; 43:7) applied to Israel as YHWH's crafted work. 'For myself' (li = for/to me) — Israel's existence is not self-referential but YHWH-referential. 'My praise they will tell' (tehillati yesapperu = my praise they will declare) — the sappar (to declare, tell, recount) of YHWH's tehillah (praise/glory = his praiseworthiness). The purpose: Israel is the praise-declaring community. Exod 19:6 ('a kingdom of priests and a holy nation'); 1 Pet 2:9 ('a royal priesthood, a holy nation, a people belonging to God, that you may declare the praises of him who called you out of darkness into his wonderful light') applies this purpose-statement to the church. The mkt-context of this verse: the entire history of Israel — creation, exodus, exile, restoration — is teleologically oriented toward the praise of YHWH.</p>",
    "22": "<p>'Yet, Jacob, you have not called on me; you have grown weary of me, O Israel' — the indictment pivoting from the restoration promise (vv18-21) to Israel's failure: 'velo oti qara'ta Ya'aqov ki-yag'ata bi Yisrael, and not me you have called on, Jacob; for you have grown weary of me, Israel.' The pivot from 'I formed you for my praise' (v21) to 'you have not called on me' = the gap between YHWH's purpose for Israel and Israel's actual practice. The 'not called on me' (lo qara'ta = did not call on me) = the failure of prayer and worship — YHWH as the partner who was not sought. 'You have grown weary of me' (ki yag'ata bi = for you have been wearied by me) — the irony: YHWH does not grow weary (40:28: 'he will not grow faint or weary') but Israel has grown weary of him. The spiritual exhaustion of a community that found YHWH's demands burdensome.</p>",
    "23": "<p>'You have not brought me sheep for burnt offerings, and your sacrifices have not honored me. I have not burdened you with grain offerings or wearied you with incense' — the inversion of the typical sacrifice-complaint: not that Israel brought bad sacrifices but that they did not bring even the sheep, and YHWH had not required the heavy tribute they apparently imagined. 'Lo-heveeta li seh olotekhah, you did not bring me a sheep of your burnt offerings' — the most basic sacrifice not offered. 'Uvezevachekhah lo kibadtani, and with your sacrifices you did not honor me' — the honor (kabod = weight/glory) that sacrifice was designed to render was not rendered. But YHWH reverses the blame: 'lo he'avadtikha beminchah, I did not burden you with a grain offering.' The he'avadtikha (I did not make you serve/labor = I did not burden you as a slave-driver) — YHWH's requirements were not excessive. 'Nor wearied you with incense' (velo yega'tikhah billevonah = and I did not weary you with frankincense) — YHWH's actual requirements were light; Israel's complaint of burden was unjustified.</p>",
    "24": "<p>'You have not bought me fragrant calamus with money, nor have you satisfied me with the fat of your sacrifices. But you have burdened me with your sins and wearied me with your iniquities' — the reversal of burden: 'lo-qanita li vekhessef qaneh, you did not buy for me with silver the calamus.' The qaneh (fragrant calamus/reed = the spice used in the anointing oil of Exod 30:23 and the sacred incense blend) is expensive — it had to be purchased. Israel did not buy even this. 'Nor have you satisfied me with the fat of your sacrifices' (vechelev zevachekhah lo hirvitani = and the fat of your sacrifices you did not satisfy/drench me). The irony reversal: 'But you have burdened me with your sins' (akh he'avadtani bechattotekha = but you have made me labor/serve with your sins) and 'wearied me with your iniquities' (yega'tani ba'avonotekha = you have wearied me with your iniquities). The same vocabulary of burdening and wearying (avad and yaga) that YHWH refused to apply to his requirements is now attributed to Israel's sin — sin burdens and wearies even YHWH.</p>",
    "25": "<p>'I, I am the one who blots out your transgressions for my own sake, and I will not remember your sins' — the grace counter-response: 'anoki anoki hu mocheh feshaekhah lema'ani, I, I am he who blots out your transgressions, for my own sake.' The emphatic anoki anoki (I, I = the same double pronoun as v11's 'I, I am the LORD') = maximum divine emphasis. The mocheh (blots out = to wipe a surface clean, Exod 32:32-33: Moses asks YHWH to blot his name out of the book; Ps 51:1,9: 'blot out my transgressions... blot out all my iniquity'). Crucially: 'lema'ani = for my own sake/for myself' — the forgiveness is self-motivated, grounded in YHWH's own character and will rather than in Israel's repentance or merit. The divine freedom to forgive purely out of sovereign grace. 'And I will not remember your sins' (vechatotekha lo ezkor = and your sins I will not remember) — the divine amnesia of forgiveness: not that YHWH loses information but that he chooses not to rehearse the sins in future judgment (Jer 31:34: 'I will forgive their wickedness and will remember their sins no more').</p>",
    "26": "<p>'Put me in remembrance; let us argue the matter together. Present your case, that you may be proved innocent' — the invitation to legal self-defense after the stunning grace of v25: 'hazkireni nishapetah yachdav, remind me, let us plead together.' The challenge: 'sapper attah lema'an titsddaq, you tell/recount so that you may be declared right.' YHWH invites Israel to present whatever case it can muster for its own innocence. The divine courtroom is open, the charges have been laid (vv22-24), and yet the invitation is genuinely offered — YHWH is not conducting a show trial but a real one. The irony: after v25's radical grace ('I blot out your transgressions for my own sake'), the invitation to 'be proved innocent' is somewhat ironic — Israel cannot prove its innocence (vv27-28 will confirm its guilt), but the offer of legal hearing is itself evidence of YHWH's commitment to fair process even in the act of grace.</p>",
    "27": "<p>'Your first ancestor sinned, and your intermediaries have rebelled against me' — the verdict of the divine courtroom: 'avikha harishon chata umelitsaiykhah pash'a vi, your first father sinned and your interpreters/mediators have rebelled against me.' The 'first ancestor' (avikha harishon = your first father): most likely a reference to Jacob/Israel (the ancestor who gave the nation its name and who himself was a deceiver from birth, Gen 25:26; 27:36) rather than Adam, in context of the Jacob/Israel address of this chapter. The 'intermediaries' (melietsaiykhah = your interpreters/mediators = those who speak on behalf of Israel before YHWH: could be prophets, priests, or kings — all of whom 'rebelled'). The guilt is comprehensive: from the founding ancestor through all the institutional mediators — the entire covenant history is a story of rebellion. This explains why the forgiveness of v25 must be purely for YHWH's own sake — there is no innocence anywhere in Israel's leadership to appeal to.</p>",
    "28": "<p>'So I allowed the sanctuary's leaders to be defiled, and I gave Jacob over to destruction and Israel to scorn' — the consequence of the foundational sin: 'va'achalel sarei qodesh, and I desecrated/defiled the leaders of the sanctuary.' The achalel (profaned/defiled = from chalal = to pierce, defile, make common; the same root as challelhu = the profaning of the Sabbath in Exod 31:14) applied to the sarei qodesh (the leaders of the sanctuary = the priests and Levitical leaders). The desecration of the sanctuary leadership was the consequence of the ancestors' sin cascading through generations. 'And I gave Jacob over to destruction' (ve'etten lachereim Ya'aqov = and I gave Jacob to the ban/destruction). The cherem (the sacred ban/destruction = the same term as YHWH's ban on the nations in 34:2; the military-religious term for total destruction applied now to Jacob). 'And Israel to scorn' (veYisrael ligduphim = and Israel to curses/reproaches) — the public humiliation of the Babylonian exile as YHWH's judicial act. The ending of ch.43 without a final comfort note is intentional: the weight of inherited sin is the theological foundation for the grace-announcement that begins ch.44.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
